84	// ---------------------------------------------------------------------------
85	// Discount strategies
86	// ---------------------------------------------------------------------------
87	
88	interface DiscountStrategy {
89	  readonly name: string;
90	  applies(order: Order): boolean;
91	  apply(subtotal: number): number;
92	}
93	
94	class BulkDiscountStrategy implements DiscountStrategy {
95	  readonly name = "bulk";
96	
97	  private totalQuantity(order: Order): number {
98	    let totalQuantity = 0;
99	    for (const item of order.items) {
100	      totalQuantity += item.quantity;
101	    }
102	    return totalQuantity;
103	  }
104	
105	  applies(order: Order): boolean {
106	    return this.totalQuantity(order) >= 10;
107	  }
108	
109	  apply(subtotal: number): number {
110	    return subtotal * 0.9;
111	  }
112	}
113	
114	class MultiLineDiscountStrategy implements DiscountStrategy {
115	  readonly name = "multi-line";
116	
117	  private distinctLineNames(order: Order): string[] {
118	    const seen: string[] = [];
119	    for (const item of order.items) {
120	      let alreadySeen = false;
121	      for (const name of seen) {
122	        if (name === item.name) {
123	          alreadySeen = true;
124	        }
125	      }
126	      if (!alreadySeen) {
127	        seen.push(item.name);
128	      }
129	    }
130	    return seen;
131	  }
132	
133	  applies(order: Order): boolean {
134	    return this.distinctLineNames(order).length >= 3;
135	  }
136	
137	  apply(subtotal: number): number {
138	    return subtotal * 0.98;
139	  }
140	}
