185	  vatRate?: number;
186	  /** Only half-up rounding is implemented; the enum anticipates bankers'. */
187	  roundingMode?: "half-up";
188	  /** Reserved for localised price formatting. */
189	  locale?: string;
190	  /** Observability hooks invoked around every pipeline stage. */
191	  hooks?: PricingHooks;
