228	  readonly currency = "EUR";
229	
230	  round(value: number): number {
231	    const scaled = value * 100;
232	    const rounded = Math.round(scaled);
233	    return rounded / 100;
234	  }
235	}
236	
237	class UsdRoundingPolicy implements RoundingPolicy {
238	  readonly currency = "USD";
239	
240	  round(value: number): number {
241	    const cents = Math.round(value * 100);
242	    return cents / 100;
243	  }
244	}
