1	// Test suite for the pricing module. Run with: npx tsx --test <this file>
2	import { test } from "node:test";
3	import assert from "node:assert/strict";
4	
5	import { computePrice, PricingFacade, type Order } from "./pricing.ts";
6	
7	function order(overrides: Partial<Order> = {}): Order {
8	  return {
9	    items: [{ name: "widget", unitPrice: 10, quantity: 2 }],
10	    currency: "GBP",
11	    loyaltyMember: false,
12	    ...overrides,
13	  };
14	}
15	
16	test("prices a plain order: subtotal plus 20% VAT", () => {
17	  // 10 * 2 = 20; VAT 20% -> 24.00
18	  assert.equal(computePrice(order()), 24);
19	});
20	
21	test("applies the bulk discount at 10 or more total units", () => {
22	  // 10 * 10 = 100; bulk -10% -> 90; VAT -> 108.00
23	  const o = order({ items: [{ name: "widget", unitPrice: 10, quantity: 10 }] });
24	  assert.equal(computePrice(o), 108);
25	});
26	
27	test("does not apply the bulk discount below 10 total units", () => {
28	  // 10 * 9 = 90; VAT -> 108.00
29	  const o = order({ items: [{ name: "widget", unitPrice: 10, quantity: 9 }] });
30	  assert.equal(computePrice(o), 108);
31	});
32	
33	test("bulk counts total units across lines", () => {
34	  // 10*6 + 5*4 = 80; qty 10 -> bulk -> 72; VAT -> 86.40
35	  const o = order({
36	    items: [
37	      { name: "widget", unitPrice: 10, quantity: 6 },
38	      { name: "gadget", unitPrice: 5, quantity: 4 },
39	    ],
40	  });
41	  assert.equal(computePrice(o), 86.4);
42	});
43	
44	test("applies the loyalty discount for members", () => {
45	  // 20; loyalty -5% -> 19; VAT -> 22.80
46	  const o = order({ loyaltyMember: true });
47	  assert.equal(computePrice(o), 22.8);
48	});
49	
50	test("applies the multi-line discount at 3 or more distinct lines", () => {
51	  // 10 + 5 + 5 = 20; multi-line -2% -> 19.6; VAT -> 23.52
52	  const o = order({
53	    items: [
54	      { name: "widget", unitPrice: 10, quantity: 1 },
55	      { name: "gadget", unitPrice: 5, quantity: 1 },
56	      { name: "gizmo", unitPrice: 5, quantity: 1 },
57	    ],
58	  });
59	  assert.equal(computePrice(o), 23.52);
60	});
61	
62	test("counts distinct line names, not lines, for the multi-line discount", () => {
63	  // Two lines share a name: only 2 distinct -> no discount. 20; VAT -> 24.00
64	  const o = order({
65	    items: [
66	      { name: "widget", unitPrice: 10, quantity: 1 },
67	      { name: "widget", unitPrice: 5, quantity: 1 },
68	      { name: "gadget", unitPrice: 5, quantity: 1 },
69	    ],
70	  });
71	  assert.equal(computePrice(o), 24);
72	});
73	
74	test("stacks bulk then loyalty discounts", () => {
75	  // 100; bulk -> 90; loyalty -> 85.5; VAT -> 102.60
76	  const o = order({
77	    items: [{ name: "widget", unitPrice: 10, quantity: 10 }],
78	    loyaltyMember: true,
